<script setup lang="ts">import{onMounted,ref,watch}from'vue';import PageState from'../components/feedback/PageState.vue';import VisitDetailDrawer from'../features/records/VisitDetailDrawer.vue';import{listVisits}from'../services/management/records';import{useSceneStore}from'../stores/scene';import type{VisitRecord}from'../types/records';const scene=useSceneStore(),items=ref<VisitRecord[]>([]),loading=ref(true),error=ref(''),userId=ref(''),dateFrom=ref(''),dateTo=ref(''),selected=ref<VisitRecord|null>(null);async function load(){if(!scene.currentSceneId){loading.value=false;return}loading.value=true;try{items.value=(await listVisits({sceneId:scene.currentSceneId,userId:userId.value,dateFrom:dateFrom.value,dateTo:dateTo.value,pageSize:100})).data.items}catch(e){error.value=e instanceof Error?e.message:'游览记录加载失败'}finally{loading.value=false}}onMounted(load);watch(()=>scene.currentSceneId,load)</script>
<template><div class="page"><header><p>DATA TRACE</p><h1>游览记录</h1><span>按用户和日期追踪每日游览会话</span></header><section class="filters"><input v-model.trim="userId" placeholder="用户 ID"/><input v-model="dateFrom" type="date"/><input v-model="dateTo" type="date"/><button @click="load">查询</button></section><PageState v-if="loading&&items.length===0" status="loading"/><PageState v-else-if="error" status="error" :description="error" @retry="load"/><PageState v-else-if="items.length===0" status="empty" title="暂无游览记录"/><section v-else class="table"><table><thead><tr><th>日期</th><th>用户</th><th>开始时间</th><th>最近打卡</th><th>操作</th></tr></thead><tbody><tr v-for="v in items" :key="v.id"><td>{{v.local_date}}</td><td><code>{{v.user_id}}</code></td><td>{{v.started_at}}</td><td>{{v.last_checkin_at||'暂无'}}</td><td><button @click="selected=v">查看轨迹</button></td></tr></tbody></table></section><VisitDetailDrawer :model-value="Boolean(selected)" :visit="selected" @update:model-value="!$event&&(selected=null)"/></div></template>
<style scoped>@import '../styles/records-page.css';</style>
